const flySpine = effectNode.getComponent( BaseSpine );
if ( !flySpine )
{
    log( "[FlyManager] PlayFlyToCollectAnimation 失敗: 無法取得 BaseSpine 元件" );
    PrefabPoolManager.GetInstance().ReturnNode( CashType.Cash.toString(), effectNode );
    callback?.();
    return;
}

flySpine.SetNodeActivity( true );
const dirSuffix = endWorldPosition.x <= startWorldPosition.x ? "_L" : "_R";
const startBoneName = isLong ? `Long_Start_Control${dirSuffix}` : `Short_Start_Control${dirSuffix}`;
const endBoneName = isLong ? `Long_End_Control${dirSuffix}` : `Short_End_Control${dirSuffix}`;
const startBone = flySpine.Spine.findBone( startBoneName );
const endBone = flySpine.Spine.findBone( endBoneName );
if ( !startBone || !endBone )
{
    log( `[FlyManager] PlayFlyToCollectAnimation 失敗: 無法找到 Spine Bone(${startBoneName}/${endBoneName})` );
    flySpine.SetNodeActivity( false );
    PrefabPoolManager.GetInstance().ReturnNode( CashType.Cash.toString(), effectNode );
    callback?.();
    return;
}

// Spine bone 的座標系以 sp.Skeleton 所在節點為基準。
// 若用 flySpine.node（外層節點）去換算，遇到父節點 scale 變動時容易偏移（飛過頭）。
const spineNode = flySpine.Spine?.node ?? flySpine.node;
const startLocalPos = getNodeSpaceAR( spineNode, startWorldPosition );
const endLocalPos = getNodeSpaceAR( spineNode, endWorldPosition );

const controller = effectNode.getComponent( FlyToCollectController );


// 播放動畫並套用骨頭位置（參照 PlayCollectTrailEffect）
const animName = isLong ? `Long_Trail_Up${dirSuffix}` : `Short_Trail_Up${dirSuffix}`;
const spineAnim = flySpine.Spine.findAnimation( animName );
const animDuration = spineAnim?.duration ?? 1;

flySpine.PlayAnimation( animName );

