+     */
+    private async PlayFeatureWheelTrailAnimation(
+        colIndex: number,
+        startWorldPosition: Vec3,
+        endWorldPosition: Vec3,
+        skinName: string,
+        callback?: () => void
+    ): Promise<void>
+    {
+        // 依終點盤面 column 選左/右 Trail（0~2 左、3~5 右）
+        const useLeft = colIndex < FlyManager.FEATURE_TRAIL_LR_SPLIT;
+        const poolKey = useLeft ? FlyManager.FEATURE_TRAIL_POOL_KEY_L : FlyManager.FEATURE_TRAIL_POOL_KEY_R;
+        const prefab = useLeft ? this.m_featureTrailPrefabL : this.m_featureTrailPrefabR;
+
+        if ( !prefab )
+        {
+            log( `[FlyManager] PlayFeatureWheelTrailAnimation 失敗: 未設定 ${useLeft ? "m_featureTrailPrefabL" : "m_featureTrailPrefabR"}（colIndex=${colIndex}）` );
+            callback?.();
+            return;
+        }
+
+        let effectNode: Node = null;
+        try
+        {
+            effectNode = PrefabPoolManager.GetInstance().GetNode( poolKey, this.node );
+            if ( !effectNode )
+            {
+                log( "[FlyManager] PlayFeatureWheelTrailAnimation 失敗: 無法建立 Trail 節點" );
+                callback?.();
+                return;
+            }
+
+            const trailSpine = effectNode.getComponent( BaseSpine );
+            if ( !trailSpine || !trailSpine.Spine )
+            {
+                log( "[FlyManager] PlayFeatureWheelTrailAnimation 失敗: 無法取得 BaseSpine 元件" );
+                PrefabPoolManager.GetInstance().ReturnNode( poolKey, effectNode );
+                callback?.();
+                return;
+            }
+
+            // Spine 產生於起點
+            trailSpine.SetNodeActivity( true );
+            effectNode.setWorldPosition( startWorldPosition );
+
+            // 左右 Spine 的 start/end bone 命名不同：左 "Trail_Start"/"Trail_End_Control"、右 "Trail_Start_R"/"Trail_End_Control_R"
+            const startBoneName = useLeft ? "Trail_Start" : "Trail_Start_R";
+            const endBoneName = useLeft ? "Trail_End_Control" : "Trail_End_Control_R";
+            const startBone = trailSpine.Spine.findBone( startBoneName );
+            const endBone = trailSpine.Spine.findBone( endBoneName );
+            if ( !startBone || !endBone )
+            {
+                log( `[FlyManager] PlayFeatureWheelTrailAnimation 失敗: 無法找到 Spine Bone(${startBoneName}/${endBoneName})` );
+                trailSpine.SetNodeActivity( false );
+                PrefabPoolManager.GetInstance().ReturnNode( poolKey, effectNode );
+                callback?.();
+                return;
+            }
+
+            // 切 Skin（非法 fallback default），再播動畫並設 bone（座標以 spine 所在節點為基準，避父層 scale 偏移）
+            trailSpine.SetSkin( skinName || FlyManager.FEATURE_TRAIL_DEFAULT_SKIN );
+
+            const animName = FlyManager.FEATURE_TRAIL_ANIM_NAME;
+            const spineAnim = trailSpine.Spine.findAnimation( animName );
+            const animDuration = spineAnim?.duration ?? 1;
+
+            trailSpine.PlayAnimation( animName );
+
+            const spineNode = trailSpine.Spine?.node ?? trailSpine.node;
+            const startLocalPos = getNodeSpaceAR( spineNode, startWorldPosition );
+            const endLocalPos = getNodeSpaceAR( spineNode, endWorldPosition );
+            startBone.x = startLocalPos.x;
+            startBone.y = startLocalPos.y;
+            endBone.x = endLocalPos.x;
+            endBone.y = endLocalPos.y;
+
+            // 回收時長對齊加速倍率（PlayAnimation 以 Game_Define.SpeedUp 設 timeScale）
+            await Define.Wait( this, animDuration / Game_Define.SpeedUp );
+
+            trailSpine.SetNodeActivity( false );
+            if ( effectNode?.isValid )
+            {
+                PrefabPoolManager.GetInstance().ReturnNode( poolKey, effectNode );
+            }
+            callback?.();
+        }
+        catch ( error )
+        {
+            log( "[FlyManager] PlayFeatureWheelTrailAnimation error:", error );
+            if ( effectNode?.isValid )
+            {
+                PrefabPoolManager.GetInstance().ReturnNode( poolKey, effectNode );
+            }
+            callback?.();
+        }
+    }
